from __future__ import annotations

from datetime import date, datetime
from typing import Any, Literal

from pydantic import BaseModel, ConfigDict, Field

from oracle.oci_oracle_db_observability.v1.conversion import to_plain_data


class DbmBaseModel(BaseModel):
    """Base model for OCI DBM MCP schemas."""

    model_config = ConfigDict(
        alias_generator=None,
        arbitrary_types_allowed=True,
        extra="allow",
        populate_by_name=True,)

    @classmethod
    def from_oci(cls, value: Any):
        return cls.model_validate(to_plain_data(value))


class DbmRequestModel(DbmBaseModel):
    """Base model for OCI DBM request schemas."""

    model_config = ConfigDict(
        alias_generator=None,
        arbitrary_types_allowed=True,
        extra="forbid",
        populate_by_name=True,)


CompartmentAccessLevel = Literal["ANY", "ACCESSIBLE"]
CompartmentLifecycleState = Literal["CREATING", "ACTIVE", "INACTIVE", "DELETING", "DELETED", "UNKNOWN_ENUM_VALUE"]


class Compartment(DbmBaseModel):
    """OCI Identity compartment metadata."""

    id: str = Field(..., description="The OCID of the compartment.")
    compartment_id: str | None = Field(None, alias="compartmentId", description="The OCID of the parent compartment.")
    name: str | None = Field(None, description="The compartment name.")
    description: str | None = Field(None, description="The compartment description.")
    lifecycle_state: CompartmentLifecycleState | None = Field(None, alias="lifecycleState", description="The current lifecycle state of the compartment.")
    time_created: datetime | None = Field(None, alias="timeCreated", description="The date and time the compartment was created.")
    inactive_status: int | None = Field(None, alias="inactiveStatus", ge=0, description="The status of the compartment if it is inactive.")
    freeform_tags: dict[str, str] | None = Field(None, alias="freeformTags", description="Free-form tags returned for the compartment.")
    defined_tags: dict[str, dict[str, Any]] | None = Field(None, alias="definedTags", description="Defined tags returned for the compartment.")
    system_tags: dict[str, dict[str, Any]] | None = Field(None, alias="systemTags", description="System tags returned for the compartment.")


class CompartmentCollection(DbmBaseModel):
    """Collection of OCI Identity compartments."""

    items: list[Compartment] = Field(..., description="Compartments returned by the list request.")
    count: int = Field(..., ge=0, description="Number of compartments returned.")


class ActivityTimeSeriesMetrics(DbmBaseModel):
    """The response object representing activityMetric details for a specific Managed Database at a particular time."""

    timestamp: datetime | None = Field(None, description='Gets the timestamp of this ActivityTimeSeriesMetrics.\nThe date and time the activity metric was created.')
    cpu_time: MetricDataPoint | None = Field(None, alias='cpuTime', description='Gets the cpu_time of this ActivityTimeSeriesMetrics.')
    wait_time: MetricDataPoint | None = Field(None, alias='waitTime', description='Gets the wait_time of this ActivityTimeSeriesMetrics.')
    user_io_time: MetricDataPoint | None = Field(None, alias='userIoTime', description='Gets the user_io_time of this ActivityTimeSeriesMetrics.')
    cpu_count: MetricDataPoint | None = Field(None, ge=0, alias='cpuCount', description='Gets the cpu_count of this ActivityTimeSeriesMetrics.')
    cluster: MetricDataPoint | None = Field(None, description='Gets the cluster of this ActivityTimeSeriesMetrics.')


class AddDataFilesDetails(DbmRequestModel):
    """The details required to add data files or temp files to the tablespace.
lease provide either credentialDetails or databaseCredential. It's recommended to provide databaseCredential"""

    credential_details: TablespaceAdminCredentialDetails | None = Field(None, alias='credentialDetails', description='Gets the credential_details of this AddDataFilesDetails.')
    database_credential: DatabaseCredentialDetails | None = Field(None, alias='databaseCredential', description='Gets the database_credential of this AddDataFilesDetails.')
    file_type: Literal['DATAFILE', 'TEMPFILE'] = Field(..., alias='fileType', description='**[Required]** Gets the file_type of this AddDataFilesDetails.\nSpecifies whether the file is a data file or temp file.\n\nAllowed values for this property are: "DATAFILE", "TEMPFILE"')
    data_files: list[str] | None = Field(None, alias='dataFiles', description='Gets the data_files of this AddDataFilesDetails.\nThe list of data files or temp files added to the tablespace.')
    file_count: int | None = Field(None, ge=0, alias='fileCount', description='Gets the file_count of this AddDataFilesDetails.\nThe number of data files or temp files to be added for the tablespace. This is for Oracle Managed Files only.')
    file_size: TablespaceStorageSize | None = Field(None, alias='fileSize', description='Gets the file_size of this AddDataFilesDetails.\nThe size of each data file or temp file.')
    is_reusable: bool | None = Field(None, alias='isReusable', description='Gets the is_reusable of this AddDataFilesDetails.\nSpecifies whether Oracle can reuse the data file or temp file. Reuse is only allowed when the file name is provided.')
    is_auto_extensible: bool | None = Field(None, alias='isAutoExtensible', description='Gets the is_auto_extensible of this AddDataFilesDetails.\nSpecifies whether the data file or temp file can be extended automatically.')
    auto_extend_next_size: TablespaceStorageSize | None = Field(None, alias='autoExtendNextSize', description='Gets the auto_extend_next_size of this AddDataFilesDetails.\nThe size of the next increment of disk space to be allocated automatically when more extents are required.')
    auto_extend_max_size: TablespaceStorageSize | None = Field(None, alias='autoExtendMaxSize', description='Gets the auto_extend_max_size of this AddDataFilesDetails.\nThe maximum disk space allowed for automatic extension of the data files or temp files.')
    is_max_size_unlimited: bool | None = Field(None, alias='isMaxSizeUnlimited', description='Gets the is_max_size_unlimited of this AddDataFilesDetails.\nSpecifies whether the disk space of the data file or temp file can be limited.')


class AddManagedDatabaseToManagedDatabaseGroupDetails(DbmRequestModel):
    """The Managed Database details required to add it to a Managed Database Group."""

    managed_database_id: str = Field(..., alias='managedDatabaseId', description='**[Required]** Gets the managed_database_id of this AddManagedDatabaseToManagedDatabaseGroupDetails. The OCID of the Managed Database.')


class AddmTaskSummary(DbmBaseModel):
    """The object containing the ADDM task metadata."""

    task_name: str | None = Field(None, alias='taskName', description='Gets the task_name of this AddmTaskSummary.\nThe name of the ADDM task.')
    task_id: int = Field(..., alias='taskId', description='**[Required]** Gets the task_id of this AddmTaskSummary.\nThe ID number of the ADDM task.')
    description: str | None = Field(None, description='Gets the description of this AddmTaskSummary.\nThe description of the ADDM task.')
    db_user: str | None = Field(None, alias='dbUser', description='Gets the db_user of this AddmTaskSummary.\nThe database user who owns the ADDM task.')
    status: Literal['INITIAL', 'EXECUTING', 'INTERRUPTED', 'COMPLETED', 'ERROR', 'UNKNOWN_ENUM_VALUE'] | None = Field(None, description='Gets the status of this AddmTaskSummary.\nThe status of the ADDM task.\n\nAllowed values for this property are: "INITIAL", "EXECUTING", "INTERRUPTED", "COMPLETED", "ERROR", \'UNKNOWN_ENUM_VALUE\'.\nAny unrecognized values returned by a service will be mapped to \'UNKNOWN_ENUM_VALUE\'.')
    time_created: datetime = Field(..., alias='timeCreated', description='**[Required]** Gets the time_created of this AddmTaskSummary.\nThe creation date of the ADDM task.')
    how_created: Literal['AUTO', 'MANUAL', 'UNKNOWN_ENUM_VALUE'] | None = Field(None, alias='howCreated', description='Gets the how_created of this AddmTaskSummary.\nA description of how the task was created.\n\nAllowed values for this property are: "AUTO", "MANUAL", \'UNKNOWN_ENUM_VALUE\'.\nAny unrecognized values returned by a service will be mapped to \'UNKNOWN_ENUM_VALUE\'.')
    start_snapshot_time: datetime | None = Field(None, alias='startSnapshotTime', description='Gets the start_snapshot_time of this AddmTaskSummary.\nThe timestamp of the beginning AWR snapshot used in the ADDM task as defined by date-time RFC3339 format.')
    end_snapshot_time: datetime | None = Field(None, alias='endSnapshotTime', description='Gets the end_snapshot_time of this AddmTaskSummary.\nThe timestamp of the ending AWR snapshot used in the ADDM task as defined by date-time RFC3339 format.')
    begin_snapshot_id: int | None = Field(None, alias='beginSnapshotId', description='Gets the begin_snapshot_id of this AddmTaskSummary.\nThe ID number of the beginning AWR snapshot.')
    end_snapshot_id: int | None = Field(None, alias='endSnapshotId', description='Gets the end_snapshot_id of this AddmTaskSummary.\nThe ID number of the ending AWR snapshot.')
    findings: int | None = Field(None, description='Gets the findings of this AddmTaskSummary.\nThe number of ADDM findings.')


class AddmTasksCollection(DbmBaseModel):
    """The list of ADDM task metadata."""

    items: list[AddmTaskSummary] = Field(..., description='**[Required]** Gets the items of this AddmTasksCollection.\nThe list of ADDM task metadata.')
    managed_database_id: str = Field(..., alias='managedDatabaseId', description='**[Required]** Gets the managed_database_id of this AddmTasksCollection. The OCID of the Managed Database.')


