    managed_database_id: str | None = Field(None, alias='managedDatabaseId', description='Gets the managed_database_id of this CreateJobDetails. The OCID of the Managed Database where the job has to be executed.')
    database_sub_type: Literal['CDB', 'PDB', 'NON_CDB', 'ACD', 'ADB'] | None = Field(None, alias='databaseSubType', description='Gets the database_sub_type of this CreateJobDetails.\nThe subtype of the Oracle Database where the job has to be executed. Only applicable when managedDatabaseGroupId is provided.\n\nAllowed values for this property are: "CDB", "PDB", "NON_CDB", "ACD", "ADB"')
    schedule_type: str = Field(..., alias='scheduleType', description='**[Required]** Gets the schedule_type of this CreateJobDetails.\nThe schedule type of the job.')
    job_type: Literal['SQL'] = Field(..., alias='jobType', description='**[Required]** Gets the job_type of this CreateJobDetails.\nThe type of job.\n\nAllowed values for this property are: "SQL"')
    timeout: str | None = Field(None, description='Gets the timeout of this CreateJobDetails.\nThe job timeout duration, which is expressed like "1h 10m 15s".')
    result_location: JobExecutionResultLocation | None = Field(None, alias='resultLocation', description='Gets the result_location of this CreateJobDetails.')
    schedule_details: JobScheduleDetails | None = Field(None, alias='scheduleDetails', description='Gets the schedule_details of this CreateJobDetails.')
    sql_text: str | None = Field(None, alias='sqlText', description='Gets the sql_text of this CreateSqlJobDetails.\nThe SQL text to be executed as part of the job.')
    in_binds: JobInBindsDetails | None = Field(None, alias='inBinds', description='Gets the in_binds of this CreateSqlJobDetails.')
    out_binds: JobOutBindsDetails | None = Field(None, alias='outBinds', description='Gets the out_binds of this CreateSqlJobDetails.')
    sql_type: str | None = Field(None, alias='sqlType', description='Gets the sql_type of this CreateSqlJobDetails.')
    operation_type: str = Field(..., alias='operationType', description='**[Required]** Gets the operation_type of this CreateSqlJobDetails.\nThe SQL operation type.')
    user_name: str | None = Field(None, alias='userName', description='Gets the user_name of this CreateSqlJobDetails.\nThe database user name used to execute the SQL job. If the job is being executed on a\nManaged Database Group, then the user name should exist on all the databases in the\ngroup with the same password.')
    password: str | None = Field(None, description='Gets the password of this CreateSqlJobDetails.\nThe password for the database user name used to execute the SQL job.')
    secret_id: str | None = Field(None, alias='secretId', description='Gets the secret_id of this CreateSqlJobDetails. The OCID of the secret containing the user password.')
    named_credential_id: str | None = Field(None, alias='namedCredentialId', description='Gets the named_credential_id of this CreateSqlJobDetails. The OCID of the Named Credentials containing password secret.')
    role: str | None = Field(None, description='Gets the role of this CreateSqlJobDetails.\nThe role of the database user. Indicates whether the database user is a normal user or sysdba.')


