class CreateTablespaceDetails(DbmRequestModel):
    """The details required to create a tablespace.
It takes either credentialDetails or databaseCredential. It's recommended to provide databaseCredential"""

    credential_details: TablespaceAdminCredentialDetails | None = Field(None, alias='credentialDetails', description='Gets the credential_details of this CreateTablespaceDetails.')
    database_credential: DatabaseCredentialDetails | None = Field(None, alias='databaseCredential', description='Gets the database_credential of this CreateTablespaceDetails.')
    name: str = Field(..., description='**[Required]** Gets the name of this CreateTablespaceDetails.\nThe name of the tablespace. It must be unique within a database.')
    type: Literal['PERMANENT', 'TEMPORARY'] | None = Field(None, description='Gets the type of this CreateTablespaceDetails.\nThe type of tablespace.\n\nAllowed values for this property are: "PERMANENT", "TEMPORARY"')
    is_bigfile: bool | None = Field(None, alias='isBigfile', description='Gets the is_bigfile of this CreateTablespaceDetails.\nSpecifies whether the tablespace is a bigfile or smallfile tablespace.\nA bigfile tablespace contains only one data file or temp file, which can contain up to approximately 4 billion (232) blocks.\nA smallfile tablespace is a traditional Oracle tablespace, which can contain 1022 data files or temp files, each of which can contain up to approximately 4 million (222) blocks.')
    data_files: list[str] | None = Field(None, alias='dataFiles', description='Gets the data_files of this CreateTablespaceDetails.\nThe list of data files or temp files created for the tablespace.')
    file_count: int | None = Field(None, ge=0, alias='fileCount', description='Gets the file_count of this CreateTablespaceDetails.\nThe number of data files or temp files created for the tablespace. This is for Oracle Managed Files only.')
    file_size: TablespaceStorageSize | None = Field(None, alias='fileSize', description='Gets the file_size of this CreateTablespaceDetails.\nThe size of each data file or temp file.')
    is_reusable: bool | None = Field(None, alias='isReusable', description='Gets the is_reusable of this CreateTablespaceDetails.\nSpecifies whether Oracle can reuse the data file or temp file. Reuse is only allowed when the file name is provided.')
    is_auto_extensible: bool | None = Field(None, alias='isAutoExtensible', description='Gets the is_auto_extensible of this CreateTablespaceDetails.\nSpecifies whether the data file or temp file can be extended automatically.')
    auto_extend_next_size: TablespaceStorageSize | None = Field(None, alias='autoExtendNextSize', description='Gets the auto_extend_next_size of this CreateTablespaceDetails.\nThe size of the next increment of disk space to be allocated automatically when more extents are required.')
    auto_extend_max_size: TablespaceStorageSize | None = Field(None, alias='autoExtendMaxSize', description='Gets the auto_extend_max_size of this CreateTablespaceDetails.\nThe maximum disk space allowed for automatic extension of the data files or temp files.')
    is_max_size_unlimited: bool | None = Field(None, alias='isMaxSizeUnlimited', description='Gets the is_max_size_unlimited of this CreateTablespaceDetails.\nSpecifies whether the disk space of the data file or temp file can be limited.')
    block_size_in_kilobytes: int | None = Field(None, alias='blockSizeInKilobytes', description='Gets the block_size_in_kilobytes of this CreateTablespaceDetails.\nBlock size for the tablespace.')
    is_encrypted: bool | None = Field(None, alias='isEncrypted', description='Gets the is_encrypted of this CreateTablespaceDetails.\nIndicates whether the tablespace is encrypted.')
    encryption_algorithm: str | None = Field(None, alias='encryptionAlgorithm', description='Gets the encryption_algorithm of this CreateTablespaceDetails.\nThe name of the encryption algorithm to be used for tablespace encryption.')
    default_compress: Literal['NO_COMPRESS', 'BASIC_COMPRESS'] | None = Field(None, alias='defaultCompress', description='Gets the default_compress of this CreateTablespaceDetails.\nThe default compression of data for all tables created in the tablespace.\n\nAllowed values for this property are: "NO_COMPRESS", "BASIC_COMPRESS"')
    status: Literal['READ_ONLY', 'READ_WRITE'] | None = Field(None, description='Gets the status of this CreateTablespaceDetails.\nThe status of the tablespace.\n\nAllowed values for this property are: "READ_ONLY", "READ_WRITE"')
    extent_management: Literal['AUTOALLOCATE', 'UNIFORM'] | None = Field(None, alias='extentManagement', description='Gets the extent_management of this CreateTablespaceDetails.\nSpecifies how the extents of the tablespace should be managed.\n\nAllowed values for this property are: "AUTOALLOCATE", "UNIFORM"')
    extent_uniform_size: TablespaceStorageSize | None = Field(None, alias='extentUniformSize', description='Gets the extent_uniform_size of this CreateTablespaceDetails.\nThe size of the extent when the tablespace is managed with uniform extents of a specific size.')
    segment_management: Literal['AUTO', 'MANUAL'] | None = Field(None, alias='segmentManagement', description='Gets the segment_management of this CreateTablespaceDetails.\nSpecifies whether tablespace segment management should be automatic or manual.\n\nAllowed values for this property are: "AUTO", "MANUAL"')
    is_default: bool | None = Field(None, alias='isDefault', description='Gets the is_default of this CreateTablespaceDetails.\nSpecifies whether the tablespace is the default tablespace.')


