    deployment_type: Literal['ONPREMISE', 'BM', 'VM', 'EXADATA', 'EXADATA_CC', 'AUTONOMOUS', 'EXADATA_XS', 'UNKNOWN_ENUM_VALUE'] = Field(..., alias='deploymentType', description='**[Required]** Gets the deployment_type of this DatabaseBackupMetrics.\nThe infrastructure used to deploy the Oracle Database.\n\nAllowed values for this property are: "ONPREMISE", "BM", "VM", "EXADATA", "EXADATA_CC", "AUTONOMOUS", "EXADATA_XS", \'UNKNOWN_ENUM_VALUE\'.\nAny unrecognized values returned by a service will be mapped to \'UNKNOWN_ENUM_VALUE\'.')
    database_version: str | None = Field(None, alias='databaseVersion', description='Gets the database_version of this DatabaseBackupMetrics.\nThe Oracle Database version.')
    workload_type: Literal['OLTP', 'DW', 'AJD', 'APEX', 'UNKNOWN_ENUM_VALUE'] | None = Field(None, alias='workloadType', description='Gets the workload_type of this DatabaseBackupMetrics.\nThe workload type of the Autonomous Database.\n\nAllowed values for this property are: "OLTP", "DW", "AJD", "APEX", \'UNKNOWN_ENUM_VALUE\'.\nAny unrecognized values returned by a service will be mapped to \'UNKNOWN_ENUM_VALUE\'.')
    database_name: str = Field(..., alias='databaseName', description='**[Required]** Gets the database_name of this DatabaseBackupMetrics.\nThe display name of the Managed Database.')
    database_id: str | None = Field(None, alias='databaseId', description='Gets the database_id of this DatabaseBackupMetrics.\nThe database ID of the Managed Database. Every database had its own ID and that value is captured here.')
    db_unique_name: str | None = Field(None, alias='dbUniqueName', description='Gets the db_unique_name of this DatabaseBackupMetrics.\nThe database unique name of the Managed Database.')
    db_role: Literal['SNAPSHOT_STANDBY', 'LOGICAL_STANDBY', 'PHYSICAL_STANDBY', 'PRIMARY', 'FAR_SYNC', 'UNKNOWN_ENUM_VALUE'] = Field(..., alias='dbRole', description='**[Required]** Gets the db_role of this DatabaseBackupMetrics.\nThe database role of the Managed Database.\n\nAllowed values for this property are: "SNAPSHOT_STANDBY", "LOGICAL_STANDBY", "PHYSICAL_STANDBY", "PRIMARY", "FAR_SYNC", \'UNKNOWN_ENUM_VALUE\'.\nAny unrecognized values returned by a service will be mapped to \'UNKNOWN_ENUM_VALUE\'.')


