class DatabaseParameterSummary(DbmBaseModel):
    """A summary of the database parameter."""

    name: str = Field(..., description='**[Required]** Gets the name of this DatabaseParameterSummary.\nThe parameter name.')
    type: Literal['BOOLEAN', 'STRING', 'INTEGER', 'FILENAME', 'BIG_INTEGER', 'RESERVED', 'UNKNOWN_ENUM_VALUE'] = Field(..., description='**[Required]** Gets the type of this DatabaseParameterSummary.\nThe parameter type.\n\nAllowed values for this property are: "BOOLEAN", "STRING", "INTEGER", "FILENAME", "BIG_INTEGER", "RESERVED", \'UNKNOWN_ENUM_VALUE\'.\nAny unrecognized values returned by a service will be mapped to \'UNKNOWN_ENUM_VALUE\'.')
