    display_value: str = Field(..., alias='displayValue', description='**[Required]** Gets the display_value of this DatabaseParameterSummary.\nThe parameter value in a user-friendly format. For example, if the `value` property shows the value 262144 for a big integer parameter, then the `displayValue` property will show the value 256K.')
    number: float | None = Field(None, description='Gets the number of this DatabaseParameterSummary.\nThe parameter number.')
    is_default: bool | None = Field(None, alias='isDefault', description='Gets the is_default of this DatabaseParameterSummary.\nIndicates whether the parameter is set to the default value (`TRUE`) or the parameter value was specified in the parameter file (`FALSE`).')
    is_session_modifiable: bool | None = Field(None, alias='isSessionModifiable', description='Gets the is_session_modifiable of this DatabaseParameterSummary.\nIndicates whether the parameter can be changed with `ALTER SESSION` (`TRUE`) or not (`FALSE`)')
    is_system_modifiable: Literal['IMMEDIATE', 'DEFERRED', 'FALSE', 'UNKNOWN_ENUM_VALUE'] | None = Field(None, alias='isSystemModifiable', description='Gets the is_system_modifiable of this DatabaseParameterSummary.\nIndicates whether the parameter can be changed with `ALTER SYSTEM` and when the change takes effect:\n- IMMEDIATE: Parameter can be changed with `ALTER SYSTEM` regardless of the type of parameter file used to start the instance. The change takes effect immediately.\n- DEFERRED: Parameter can be changed with `ALTER SYSTEM` regardless of the type of parameter file used to start the instance. The change takes effect in subsequent sessions.\n- FALSE: Parameter cannot be changed with `ALTER SYSTEM` unless a server parameter file was used to start the instance. The change takes effect in subsequent instances.\n\nAllowed values for this property are: "IMMEDIATE", "DEFERRED", "FALSE", \'UNKNOWN_ENUM_VALUE\'.\nAny unrecognized values returned by a service will be mapped to \'UNKNOWN_ENUM_VALUE\'.')
    is_pdb_modifiable: bool | None = Field(None, alias='isPdbModifiable', description='Gets the is_pdb_modifiable of this DatabaseParameterSummary.\nIndicates whether the parameter can be modified on a per-PDB basis (`TRUE`) or not (`FALSE`). In a non-CDB, the value of this property is `null`.')
    is_instance_modifiable: bool | None = Field(None, alias='isInstanceModifiable', description='Gets the is_instance_modifiable of this DatabaseParameterSummary.\nFor parameters that can be changed with `ALTER SYSTEM`, indicates whether the value of the parameter can be different for every instance (`TRUE`) or whether the parameter must have the same value for all Real Application Clusters instances (`FALSE`). For other parameters, this is always `FALSE`.')
    is_modified: Literal['MODIFIED', 'FALSE', 'UNKNOWN_ENUM_VALUE'] | None = Field(None, alias='isModified', description='Gets the is_modified of this DatabaseParameterSummary.\nIndicates how the parameter was modified. If an `ALTER SYSTEM` was performed, the value will be `MODIFIED`.\n\nAllowed values for this property are: "MODIFIED", "FALSE", \'UNKNOWN_ENUM_VALUE\'.\nAny unrecognized values returned by a service will be mapped to \'UNKNOWN_ENUM_VALUE\'.')
    is_adjusted: bool | None = Field(None, alias='isAdjusted', description='Gets the is_adjusted of this DatabaseParameterSummary.\nIndicates whether Oracle adjusted the input value to a more suitable value.')
    is_deprecated: bool | None = Field(None, alias='isDeprecated', description='Gets the is_deprecated of this DatabaseParameterSummary.\nIndicates whether the parameter has been deprecated (`TRUE`) or not (`FALSE`).')
    is_basic: bool | None = Field(None, alias='isBasic', description='Gets the is_basic of this DatabaseParameterSummary.\nIndicates whether the parameter is a basic parameter (`TRUE`) or not (`FALSE`).')
    description: str | None = Field(None, description='Gets the description of this DatabaseParameterSummary.\nThe description of the parameter.')
    ordinal: float | None = Field(None, description='Gets the ordinal of this DatabaseParameterSummary.\nThe position (ordinal number) of the parameter value. Useful only for parameters whose values are lists of strings.')
    update_comment: str | None = Field(None, alias='updateComment', description='Gets the update_comment of this DatabaseParameterSummary.\nThe comments associated with the most recent update.')
    container_id: float | None = Field(None, alias='containerId', description='Gets the container_id of this DatabaseParameterSummary.\nThe ID of the database container to which the data pertains.\nPossible values include:\n- `0`: This value is used for data that pertain to the entire CDB. This value is also used for data in non-CDBs.\n- `1`: This value is used for data that pertain to only the root container.\n- `n`: Where n is the applicable container ID for the data.')
    category: str | None = Field(None, description='Gets the category of this DatabaseParameterSummary.\nThe parameter category.')
    constraint: Literal['UNIQUE', 'IDENTICAL', 'NONE', 'UNKNOWN_ENUM_VALUE'] | None = Field(None, description='Gets the constraint of this DatabaseParameterSummary.\nApplicable in case of Oracle Real Application Clusters (Oracle RAC) databases.\nA `UNIQUE` parameter is one which is unique to each Oracle Real Application\nClusters (Oracle RAC) instance. For example, the parameter `INSTANCE_NUMBER`\nmust have different values in each instance. An `IDENTICAL` parameter must\nhave the same value for every instance. For example, the parameter\n`DB_BLOCK_SIZE` must have the same value in all instances.\n\nAllowed values for this property are: "UNIQUE", "IDENTICAL", "NONE", \'UNKNOWN_ENUM_VALUE\'.\nAny unrecognized values returned by a service will be mapped to \'UNKNOWN_ENUM_VALUE\'.')
    sid: str | None = Field(None, description='Gets the sid of this DatabaseParameterSummary.\nThe database instance SID for which the parameter is defined.')
    is_specified: bool | None = Field(None, alias='isSpecified', description='Gets the is_specified of this DatabaseParameterSummary.\nIndicates whether the parameter was specified in the server parameter file (`TRUE`) or not (`FALSE`). Applicable only when the parameter source is `SPFILE`.')
    allowed_values: list[AllowedParameterValue] | None = Field(None, alias='allowedValues', description='Gets the allowed_values of this DatabaseParameterSummary.\nA list of allowed values for this parameter.')


