    id: str = Field(..., description='**[Required]** Gets the id of this Job. The OCID of the job.')
    compartment_id: str = Field(..., alias='compartmentId', description='**[Required]** Gets the compartment_id of this Job. The OCID of the compartment in which the job resides.')
    name: str = Field(..., description='**[Required]** Gets the name of this Job.\nThe display name of the job.')
    description: str | None = Field(None, description='Gets the description of this Job.\nThe description of the job.')
    managed_database_group_id: str | None = Field(None, alias='managedDatabaseGroupId', description='Gets the managed_database_group_id of this Job. The OCID of the Managed Database Group where the job has to be executed.')
    managed_database_id: str | None = Field(None, alias='managedDatabaseId', description='Gets the managed_database_id of this Job. The OCID of the Managed Database where the job has to be executed.')
    managed_databases_details: list[JobDatabase] | None = Field(None, alias='managedDatabasesDetails', description='Gets the managed_databases_details of this Job.\nThe details of the Managed Databases where the job has to be executed.')
    database_sub_type: Literal['CDB', 'PDB', 'NON_CDB', 'ACD', 'ADB', 'UNKNOWN_ENUM_VALUE'] | None = Field(None, alias='databaseSubType', description='Gets the database_sub_type of this Job.\nThe subtype of the Oracle Database where the job has to be executed. Applicable only when managedDatabaseGroupId is provided.\n\nAllowed values for this property are: "CDB", "PDB", "NON_CDB", "ACD", "ADB", \'UNKNOWN_ENUM_VALUE\'.\nAny unrecognized values returned by a service will be mapped to \'UNKNOWN_ENUM_VALUE\'.')
    schedule_type: Literal['IMMEDIATE', 'LATER', 'UNKNOWN_ENUM_VALUE'] = Field(..., alias='scheduleType', description='**[Required]** Gets the schedule_type of this Job.\nThe schedule type of the job.\n\nAllowed values for this property are: "IMMEDIATE", "LATER", \'UNKNOWN_ENUM_VALUE\'.\nAny unrecognized values returned by a service will be mapped to \'UNKNOWN_ENUM_VALUE\'.')
    job_type: Literal['SQL', 'UNKNOWN_ENUM_VALUE'] = Field(..., alias='jobType', description='**[Required]** Gets the job_type of this Job.\nThe type of job.\n\nAllowed values for this property are: "SQL", \'UNKNOWN_ENUM_VALUE\'.\nAny unrecognized values returned by a service will be mapped to \'UNKNOWN_ENUM_VALUE\'.')
    lifecycle_state: Literal['ACTIVE', 'INACTIVE', 'UNKNOWN_ENUM_VALUE'] = Field(..., alias='lifecycleState', description='**[Required]** Gets the lifecycle_state of this Job.\nThe lifecycle state of the job.\n\nAllowed values for this property are: "ACTIVE", "INACTIVE", \'UNKNOWN_ENUM_VALUE\'.\nAny unrecognized values returned by a service will be mapped to \'UNKNOWN_ENUM_VALUE\'.')
    timeout: str | None = Field(None, description='Gets the timeout of this Job.\nThe job timeout duration, which is expressed like "1h 10m 15s".')
    result_location: JobExecutionResultLocation | None = Field(None, alias='resultLocation', description='Gets the result_location of this Job.')
    schedule_details: JobScheduleDetails | None = Field(None, alias='scheduleDetails', description='Gets the schedule_details of this Job.')
    submission_error_message: str | None = Field(None, alias='submissionErrorMessage', description='Gets the submission_error_message of this Job.\nThe error message that is returned if the job submission fails. Null is returned in all other scenarios.')
    time_created: datetime = Field(..., alias='timeCreated', description='**[Required]** Gets the time_created of this Job.\nThe date and time when the job was created.')
    time_updated: datetime = Field(..., alias='timeUpdated', description='**[Required]** Gets the time_updated of this Job.\nThe date and time when the job was last updated.')


