    job_type: Literal['SQL', 'UNKNOWN_ENUM_VALUE'] = Field(..., alias='jobType', description='**[Required]** Gets the job_type of this JobSummary.\nThe type of job.\n\nAllowed values for this property are: "SQL", \'UNKNOWN_ENUM_VALUE\'.\nAny unrecognized values returned by a service will be mapped to \'UNKNOWN_ENUM_VALUE\'.')
    lifecycle_state: str = Field(..., alias='lifecycleState', description='**[Required]** Gets the lifecycle_state of this JobSummary.\nThe lifecycle state of the job.')
    timeout: str | None = Field(None, description='Gets the timeout of this JobSummary.\nThe job timeout duration, which is expressed like "1h 10m 15s".')
    submission_error_message: str | None = Field(None, alias='submissionErrorMessage', description='Gets the submission_error_message of this JobSummary.\nThe error message that is returned if the job submission fails. Null is returned in all other scenarios.')
