class SqlPlanBaseline(DbmBaseModel):
    """The details of a SQL plan baseline."""

    plan_name: str = Field(..., alias='planName', description='**[Required]** Gets the plan_name of this SqlPlanBaseline.\nThe unique plan identifier.')
    sql_handle: str = Field(..., alias='sqlHandle', description='**[Required]** Gets the sql_handle of this SqlPlanBaseline.\nThe unique SQL identifier.')
    sql_text: str = Field(..., alias='sqlText', description='**[Required]** Gets the sql_text of this SqlPlanBaseline.\nThe SQL text.')
    origin: Literal['ADDM_SQLTUNE', 'AUTO_CAPTURE', 'AUTO_SQLTUNE', 'EVOLVE_AUTO_INDEX_LOAD', 'EVOLVE_CREATE_FROM_ADAPTIVE', 'EVOLVE_LOAD_FROM_STS', 'EVOLVE_LOAD_FROM_AWR', 'EVOLVE_LOAD_FROM_CURSOR_CACHE', 'MANUAL_LOAD', 'MANUAL_LOAD_FROM_AWR', 'MANUAL_LOAD_FROM_CURSOR_CACHE', 'MANUAL_LOAD_FROM_STS', 'MANUAL_SQLTUNE', 'STORED_OUTLINE', 'UNKNOWN', 'UNKNOWN_ENUM_VALUE'] | None = Field(None, description='Gets the origin of this SqlPlanBaseline.\nThe origin of the SQL plan baseline.\n\nAllowed values for this property are: "ADDM_SQLTUNE", "AUTO_CAPTURE", "AUTO_SQLTUNE", "EVOLVE_AUTO_INDEX_LOAD", "EVOLVE_CREATE_FROM_ADAPTIVE", "EVOLVE_LOAD_FROM_STS", "EVOLVE_LOAD_FROM_AWR", "EVOLVE_LOAD_FROM_CURSOR_CACHE", "MANUAL_LOAD", "MANUAL_LOAD_FROM_AWR", "MANUAL_LOAD_FROM_CURSOR_CACHE", "MANUAL_LOAD_FROM_STS", "MANUAL_SQLTUNE", "STORED_OUTLINE", "UNKNOWN", \'UNKNOWN_ENUM_VALUE\'.\nAny unrecognized values returned by a service will be mapped to \'UNKNOWN_ENUM_VALUE\'.')
    time_created: datetime = Field(..., alias='timeCreated', description='**[Required]** Gets the time_created of this SqlPlanBaseline.\nThe date and time when the plan baseline was created.')
    time_last_modified: datetime | None = Field(None, alias='timeLastModified', description='Gets the time_last_modified of this SqlPlanBaseline.\nThe date and time when the plan baseline was last modified.')
    time_last_executed: datetime | None = Field(None, alias='timeLastExecuted', description='Gets the time_last_executed of this SqlPlanBaseline.\nThe date and time when the plan baseline was last executed.\n\n**Note:** For performance reasons, database does not update this value\nimmediately after each execution of the plan baseline. Therefore, the plan\nbaseline may have been executed more recently than this value indicates.')
    enabled: Literal['YES', 'NO', 'UNKNOWN_ENUM_VALUE'] | None = Field(None, description='Gets the enabled of this SqlPlanBaseline.\nIndicates whether the plan baseline is enabled (`YES`) or disabled (`NO`).\n\nAllowed values for this property are: "YES", "NO", \'UNKNOWN_ENUM_VALUE\'.\nAny unrecognized values returned by a service will be mapped to \'UNKNOWN_ENUM_VALUE\'.')
    accepted: Literal['YES', 'NO', 'UNKNOWN_ENUM_VALUE'] | None = Field(None, description='Gets the accepted of this SqlPlanBaseline.\nIndicates whether the plan baseline is accepted (`YES`) or not (`NO`).\n\nAllowed values for this property are: "YES", "NO", \'UNKNOWN_ENUM_VALUE\'.\nAny unrecognized values returned by a service will be mapped to \'UNKNOWN_ENUM_VALUE\'.')
    fixed: Literal['YES', 'NO', 'UNKNOWN_ENUM_VALUE'] | None = Field(None, description='Gets the fixed of this SqlPlanBaseline.\nIndicates whether the plan baseline is fixed (`YES`) or not (`NO`).\n\nAllowed values for this property are: "YES", "NO", \'UNKNOWN_ENUM_VALUE\'.\nAny unrecognized values returned by a service will be mapped to \'UNKNOWN_ENUM_VALUE\'.')
    reproduced: Literal['YES', 'NO', 'UNKNOWN_ENUM_VALUE'] | None = Field(None, description='Gets the reproduced of this SqlPlanBaseline.\nIndicates whether the optimizer was able to reproduce the plan (`YES`) or not (`NO`).\nThe value is set to `YES` when a plan is initially added to the plan baseline.\n\nAllowed values for this property are: "YES", "NO", \'UNKNOWN_ENUM_VALUE\'.\nAny unrecognized values returned by a service will be mapped to \'UNKNOWN_ENUM_VALUE\'.')
    auto_purge: Literal['YES', 'NO', 'UNKNOWN_ENUM_VALUE'] | None = Field(None, alias='autoPurge', description='Gets the auto_purge of this SqlPlanBaseline.\nIndicates whether the plan baseline is auto-purged (`YES`) or not (`NO`).\n\nAllowed values for this property are: "YES", "NO", \'UNKNOWN_ENUM_VALUE\'.\nAny unrecognized values returned by a service will be mapped to \'UNKNOWN_ENUM_VALUE\'.')
    adaptive: Literal['YES', 'NO', 'UNKNOWN_ENUM_VALUE'] | None = Field(None, description='Gets the adaptive of this SqlPlanBaseline.\nIndicates whether a plan that is automatically captured by SQL plan management is marked adaptive or not.\n\nWhen a new adaptive plan is found for a SQL statement that has an existing SQL plan baseline, that new plan\nwill be added to the SQL plan baseline as an unaccepted plan, and the `ADAPTIVE` property will be marked `YES`.\nWhen this new plan is verified (either manually or via the auto evolve task), the plan will be test executed\nand the final plan determined at execution will become an accepted plan if its performance is better than\nthe existing plan baseline. At this point, the value of the `ADAPTIVE` property is set to `NO` since the plan\nis no longer adaptive, but resolved.\n\nAllowed values for this property are: "YES", "NO", \'UNKNOWN_ENUM_VALUE\'.\nAny unrecognized values returned by a service will be mapped to \'UNKNOWN_ENUM_VALUE\'.')
    module: str | None = Field(None, description='Gets the module of this SqlPlanBaseline.\nThe application module name.')
    action: str | None = Field(None, description='Gets the action of this SqlPlanBaseline.\nThe application action.')
    execution_plan: str = Field(..., alias='executionPlan', description='**[Required]** Gets the execution_plan of this SqlPlanBaseline.\nThe execution plan for the SQL statement.')


