    is_sql_plan_baselines_usage_enabled: bool = Field(..., alias='isSqlPlanBaselinesUsageEnabled', description='**[Required]** Gets the is_sql_plan_baselines_usage_enabled of this SqlPlanBaselineConfiguration.\nIndicates whether the database uses SQL plan baselines (`true`) or not (`false`).')
